import { useState, useEffect } from "react";
import axios from "axios";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

export default function Projectdetails() {

const [showForm, setShowForm] = useState(false);
const [projects, setProjects] = useState([]);
const [editId, setEditId] = useState(null);

const [formData, setFormData] = useState({
name:"",
location:"",
minBudget:"",
maxBudget:"",
floors:"",
area:"",
parking:"",
amenities:"",
start_date:"",
end_date:"",
duration:"",
description:"",
status:"Active"
});

useEffect(()=>{
fetchProjects();
},[]);

const fetchProjects = async ()=>{
try{
const res = await axios.get("http://localhost:5000/api/projects");
setProjects(res.data);
}catch(err){
console.error(err);
}
};

//////////////////////////////////////////////////////
// ✅ ADDED: FLOOR TIMELINE FUNCTION (NEW)
//////////////////////////////////////////////////////
const getFloorTimeline = () => {
if (!formData.start_date || !formData.end_date || !formData.floors) return [];

const start = new Date(formData.start_date);
const end = new Date(formData.end_date);

const totalYears =
(end - start) / (1000 * 60 * 60 * 24 * 365);

const timePerFloor = totalYears / formData.floors;

let timeline = [];

for (let i = 1; i <= formData.floors; i++) {

let completionDate = new Date(start);

// better accuracy using months
completionDate.setMonth(
start.getMonth() + Math.round(i * timePerFloor * 12)
);

timeline.push({
floor: i,
date: completionDate.toLocaleDateString()
});
}

return timeline;
};
//////////////////////////////////////////////////////

// HANDLE INPUT
const handleChange = (e)=>{
const {name,value} = e.target;

// NAME VALID
if (name === "name" && !/^[A-Za-z ]*$/.test(value)) return;

// LOCATION VALID
if (name === "location" && !/^[A-Za-z ]*$/.test(value)) return;

// FLOOR & AREA VALID
if (name === "floors" && value < 0) return;
if (name === "area" && value < 0) return;

let updated = { ...formData, [name]: value };

// AUTO DURATION
if(name==="start_date" || name==="end_date"){
const start = name==="start_date" ? value : formData.start_date;
const end = name==="end_date" ? value : formData.end_date;

if(start && end){
const years =
(new Date(end) - new Date(start)) /
(1000 * 60 * 60 * 24 * 365);

updated.duration = years.toFixed(2);
}
}

setFormData(updated);
};

// VALIDATION
const validateForm = ()=>{

if (!/^[A-Za-z ]+$/.test(formData.name)) {
alert("Project name only alphabets");
return false;
}

if (!/^[A-Za-z ]+$/.test(formData.location)) {
alert("Location only alphabets");
return false;
}

if (!formData.start_date || !formData.end_date) {
alert("Dates required");
return false;
}

const start = new Date(formData.start_date);
const end = new Date(formData.end_date);

if (start >= end) {
alert("End date must be after start date");
return false;
}

const diffYears = (end - start) / (1000 * 60 * 60 * 24 * 365);

if (diffYears < 1) {
alert("Minimum duration 1 year required");
return false;
}

// BUDGET
const min = Number(formData.minBudget);
const max = Number(formData.maxBudget);

if (min < 5000000) {
alert("Minimum ₹50 lakh required");
return false;
}

if (max > 100000000) {
alert("Max ₹10 crore allowed");
return false;
}

if (min >= max) {
alert("Min must be less than max");
return false;
}

if (!formData.floors || formData.floors <= 0) {
alert("Floors must be positive");
return false;
}

if (!formData.area || formData.area <= 0) {
alert("Area must be positive");
return false;
}

return true;
};

// SUBMIT
const handleSubmit = async ()=>{

if(!validateForm()) return;

try{

const payload = {
...formData,
budget: formData.maxBudget
};

if(editId){
await axios.put(`http://localhost:5000/api/projects/${editId}`, payload);
}else{
await axios.post("http://localhost:5000/api/projects/add", payload);
}

fetchProjects();

setFormData({
name:"",
location:"",
minBudget:"",
maxBudget:"",
floors:"",
area:"",
parking:"",
amenities:"",
start_date:"",
end_date:"",
duration:"",
description:"",
status:"Active"
});

setEditId(null);
setShowForm(false);

}catch(err){
console.error(err);
alert("Error saving");
}
};

// EDIT
const handleEdit = (project)=>{
setFormData({
name:project.name,
location:project.location,
minBudget:project.min_budget || "",
maxBudget:project.max_budget || "",
floors:project.floors,
area:project.area || "",
parking:project.parking || "",
amenities:project.amenities || "",
start_date:project.start_date,
end_date:project.end_date,
duration:project.duration || "",
description:project.description,
status:project.status
});
setEditId(project.id);
setShowForm(true);
};

// VIEW
const handleView = (project)=>{
alert(JSON.stringify(project,null,2));
};

return(

<div className="flex bg-gray-100 min-h-screen">

<Sidebar/>

<div className="flex-1 flex flex-col">

<Topbar/>

<div className="p-8">

{!showForm && (

<>
<div className="flex justify-between mb-6">
<h1 className="text-2xl font-bold">Projects</h1>
<button onClick={()=>setShowForm(true)} className="bg-orange-500 text-white px-4 py-2 rounded">
+ Add
</button>
</div>

<div className="grid grid-cols-3 gap-6">

{projects.map(p=>(

<div key={p.id} className="bg-white p-5 rounded shadow">

<div className="flex justify-end gap-3">
<button onClick={()=>handleEdit(p)}>✏️</button>
<button onClick={()=>handleView(p)}>👁️</button>
</div>

<h3 className="font-bold">{p.name}</h3>
<p>{p.location}</p>
<p>₹{p.budget}</p>
<p>Floors: {p.floors}</p>
<p>Parking: {p.parking}</p>
<p>Amenities: {p.amenities}</p>

</div>
))}

</div>
</>
)}

{showForm && (

<div className="bg-white p-6 rounded shadow">

<h2 className="text-xl mb-4">Project Form</h2>

<div className="grid grid-cols-2 gap-4">

{/* all your existing inputs unchanged */}

</div>

<p className="mt-2">Duration: {formData.duration || 0} yrs</p>

//////////////////////////////////////////////////////
// ✅ ADDED UI (NEW)
//////////////////////////////////////////////////////
{formData.floors > 0 && formData.duration && (
<div className="mt-4">
<h3 className="font-semibold">Floor Completion Timeline</h3>

<ul className="text-sm mt-2">
{getFloorTimeline().map((f, index) => (
<li key={index}>
Floor {f.floor} → {f.date}
</li>
))}
</ul>

</div>
)}
//////////////////////////////////////////////////////

<select name="status" value={formData.status} onChange={handleChange} className="border p-2 w-full mt-2">
<option>Active</option>
<option>Completed</option>
<option>On Hold</option>
</select>

<div className="flex gap-4 mt-4">
<button onClick={handleSubmit} className="bg-orange-500 text-white px-4 py-2 rounded">Save</button>
<button onClick={()=>setShowForm(false)} className="bg-gray-300 px-4 py-2 rounded">Cancel</button>
</div>

</div>

)}

</div>

</div>

</div>

);
}
